import React, { createContext, useContext, useReducer, useEffect } from 'react';
import apiService from '../services/api';
import { useDebounce } from '../hooks/useDebounce';

// Initial state
const initialState = {
  notes: [],
  currentNote: null,
  loading: false,
  error: null,
  searchResults: [],
  isSearching: false,
  pagination: {
    page: 1,
    limit: 20,
    total: 0
  }
};

// Action types
const ACTIONS = {
  SET_LOADING: 'SET_LOADING',
  SET_ERROR: 'SET_ERROR',
  CLEAR_ERROR: 'CLEAR_ERROR',
  SET_NOTES: 'SET_NOTES',
  SET_CURRENT_NOTE: 'SET_CURRENT_NOTE',
  UPDATE_CURRENT_NOTE: 'UPDATE_CURRENT_NOTE',
  ADD_NOTE: 'ADD_NOTE',
  UPDATE_NOTE: 'UPDATE_NOTE',
  DELETE_NOTE: 'DELETE_NOTE',
  SET_SEARCH_RESULTS: 'SET_SEARCH_RESULTS',
  SET_SEARCHING: 'SET_SEARCHING',
  SET_PAGINATION: 'SET_PAGINATION'
};

// Reducer function
const notesReducer = (state, action) => {
  switch (action.type) {
    case ACTIONS.SET_LOADING:
      return { ...state, loading: action.payload };
    
    case ACTIONS.SET_ERROR:
      return { ...state, error: action.payload, loading: false };
    
    case ACTIONS.CLEAR_ERROR:
      return { ...state, error: null };
    
    case ACTIONS.SET_NOTES:
      return { 
        ...state, 
        notes: action.payload.notes,
        pagination: action.payload.pagination,
        loading: false 
      };
    
    case ACTIONS.SET_CURRENT_NOTE:
      return { ...state, currentNote: action.payload, loading: false };
    
    case ACTIONS.UPDATE_CURRENT_NOTE:
      return { 
        ...state, 
        currentNote: state.currentNote 
          ? { ...state.currentNote, ...action.payload }
          : null 
      };
    
    case ACTIONS.ADD_NOTE:
      return { 
        ...state, 
        notes: [action.payload, ...state.notes],
        currentNote: action.payload,
        loading: false 
      };
    
    case ACTIONS.UPDATE_NOTE:
      return { 
        ...state, 
        notes: state.notes.map(note => 
          note.id === action.payload.id ? action.payload : note
        ),
        currentNote: state.currentNote?.id === action.payload.id 
          ? action.payload 
          : state.currentNote,
        loading: false 
      };
    
    case ACTIONS.DELETE_NOTE:
      return { 
        ...state, 
        notes: state.notes.filter(note => note.id !== action.payload),
        currentNote: state.currentNote?.id === action.payload ? null : state.currentNote,
        loading: false 
      };
    
    case ACTIONS.SET_SEARCH_RESULTS:
      return { 
        ...state, 
        searchResults: action.payload.notes,
        pagination: action.payload.pagination,
        isSearching: false,
        loading: false 
      };
    
    case ACTIONS.SET_SEARCHING:
      return { ...state, isSearching: action.payload };
    
    case ACTIONS.SET_PAGINATION:
      return { ...state, pagination: { ...state.pagination, ...action.payload } };
    
    default:
      return state;
  }
};

// Context creation
const NotesContext = createContext();

// Provider component
export const NotesProvider = ({ children }) => {
  const [state, dispatch] = useReducer(notesReducer, initialState);

  // Actions
  const actions = {
    setLoading: (loading) => dispatch({ type: ACTIONS.SET_LOADING, payload: loading }),
    setError: (error) => dispatch({ type: ACTIONS.SET_ERROR, payload: error }),
    clearError: () => dispatch({ type: ACTIONS.CLEAR_ERROR }),

    // Fetch notes
    fetchNotes: async (page = 1, limit = 20) => {
      try {
        actions.setLoading(true);
        actions.clearError();
        const response = await apiService.getNotes(page, limit);
        dispatch({ 
          type: ACTIONS.SET_NOTES, 
          payload: {
            notes: response.data,
            pagination: response.pagination
          }
        });
      } catch (error) {
        actions.setError(error.message);
      }
    },

    // Fetch single note
    fetchNote: async (id) => {
      try {
        actions.setLoading(true);
        actions.clearError();
        const response = await apiService.getNote(id);
        dispatch({ type: ACTIONS.SET_CURRENT_NOTE, payload: response.data });
      } catch (error) {
        actions.setError(error.message);
      }
    },

    // Create note
    createNote: async (noteData) => {
      try {
        actions.setLoading(true);
        actions.clearError();
        const response = await apiService.createNote(noteData);
        dispatch({ type: ACTIONS.ADD_NOTE, payload: response.data });
        return response.data;
      } catch (error) {
        actions.setError(error.message);
        throw error;
      }
    },

    // Update note
    updateNote: async (id, noteData) => {
      try {
        actions.setLoading(true);
        actions.clearError();
        const response = await apiService.updateNote(id, noteData);
        dispatch({ type: ACTIONS.UPDATE_NOTE, payload: response.data });
        return response.data;
      } catch (error) {
        actions.setError(error.message);
        throw error;
      }
    },

    // Delete note
    deleteNote: async (id) => {
      try {
        actions.setLoading(true);
        actions.clearError();
        await apiService.deleteNote(id);
        dispatch({ type: ACTIONS.DELETE_NOTE, payload: id });
      } catch (error) {
        actions.setError(error.message);
        throw error;
      }
    },

    // Search notes
    searchNotes: async (searchTerm, page = 1, limit = 20) => {
      try {
        dispatch({ type: ACTIONS.SET_SEARCHING, payload: true });
        actions.clearError();
        const response = await apiService.searchNotes(searchTerm, page, limit);
        dispatch({ 
          type: ACTIONS.SET_SEARCH_RESULTS, 
          payload: {
            notes: response.data,
            pagination: response.pagination
          }
        });
      } catch (error) {
        actions.setError(error.message);
      }
    },

    // Clear search
    clearSearch: () => {
      dispatch({ type: ACTIONS.SET_SEARCH_RESULTS, payload: { notes: [], pagination: { page: 1, limit: 20, total: 0 } } });
    },

    // Update current note locally (for auto-save)
    updateCurrentNoteLocally: (updates) => {
      dispatch({ type: ACTIONS.UPDATE_CURRENT_NOTE, payload: updates });
    }
  };

  // Auto-save functionality using debounce
  const debouncedCurrentNote = useDebounce(state.currentNote, 800);

  useEffect(() => {
    if (debouncedCurrentNote && debouncedCurrentNote.id) {
      // Only auto-save if there are actual changes
      const originalNote = state.notes.find(n => n.id === debouncedCurrentNote.id);
      if (originalNote && 
          (originalNote.title !== debouncedCurrentNote.title || 
           originalNote.content !== debouncedCurrentNote.content)) {
        actions.updateNote(debouncedCurrentNote.id, {
          title: debouncedCurrentNote.title,
          content: debouncedCurrentNote.content
        }).catch(console.error);
      }
    }
  }, [debouncedCurrentNote]);

  // Load initial notes
  useEffect(() => {
    actions.fetchNotes();
  }, []);

  const value = {
    ...state,
    ...actions
  };

  return (
    <NotesContext.Provider value={value}>
      {children}
    </NotesContext.Provider>
  );
};

// Custom hook to use the context
export const useNotes = () => {
  const context = useContext(NotesContext);
  if (!context) {
    throw new Error('useNotes must be used within a NotesProvider');
  }
  return context;
};

export { ACTIONS };
